import { readFile, writeFile } from "node:fs/promises";
import { join } from "node:path";

import { VisibleAutomationBrowserRun } from "./automation-browser.mjs";
import {
  ensureRetailerBrowserProfile,
  getRetailerBrowserProfileDirectory,
} from "./shopping-browser-profiles.mjs";

export const ASKET_RETAILER_IDENTIFIER = "Asket";
export const ASKET_LOGIN_URL = "https://www.asket.com/en-dk/account";
export const RETAILER_SESSION_STATUS_FILE = "retailer-session.json";
export const RETAILER_SESSION_SCHEMA_VERSION = 1;
export const RETAILER_SESSION_CONNECTED_STATUS = "connected";

export async function startAsketLoginFlow({
  browserRun,
  launcher,
  windowManager,
  chat,
  profilesRoot,
  loginUrl = ASKET_LOGIN_URL,
  waitForAuthenticated,
  now = new Date(),
} = {}) {
  const profile = await ensureRetailerBrowserProfile(ASKET_RETAILER_IDENTIFIER, profilesRoot);
  const run =
    browserRun ??
    new VisibleAutomationBrowserRun({
      launcher,
      windowManager,
      chat,
    });

  await run.startStagingRun({
    retailer: ASKET_RETAILER_IDENTIFIER,
    loginUrl,
    startUrl: loginUrl,
    userDataDir: profile.userDataDir,
  });

  const session = run.requireCurrentRun().session;
  await openLoginPage(session, loginUrl);
  const authenticated = await waitForAsketAuthentication(session, waitForAuthenticated, loginUrl);

  if (!authenticated) {
    throw new Error("Asket authentication did not complete.");
  }

  const sessionStatus = await writeRetailerSessionStatus(
    {
      retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
      status: RETAILER_SESSION_CONNECTED_STATUS,
      connectedAt: now,
    },
    profile.profileDirectory,
  );
  await run.completeSuccessfully();

  return {
    loginUrl,
    profile,
    retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
    sessionStatus,
    status: RETAILER_SESSION_CONNECTED_STATUS,
  };
}

export async function readAsketConnectionStatus(profilesRoot) {
  const profileDirectory = getRetailerBrowserProfileDirectory(
    ASKET_RETAILER_IDENTIFIER,
    profilesRoot,
  );
  return readRetailerSessionStatus(profileDirectory);
}

export async function readAsketConnectedRetailers(profilesRoot) {
  const status = await readAsketConnectionStatus(profilesRoot);
  if (status?.status !== RETAILER_SESSION_CONNECTED_STATUS) {
    return [];
  }

  return [
    {
      retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
      status: "Connected",
    },
  ];
}

export async function writeRetailerSessionStatus(status, profileDirectory) {
  const normalized = normalizeRetailerSessionStatus(status);
  await writeFile(
    join(profileDirectory, RETAILER_SESSION_STATUS_FILE),
    `${JSON.stringify(normalized, null, 2)}\n`,
    "utf8",
  );
  return normalized;
}

export async function readRetailerSessionStatus(profileDirectory) {
  try {
    const raw = await readFile(join(profileDirectory, RETAILER_SESSION_STATUS_FILE), "utf8");
    return normalizeRetailerSessionStatus(JSON.parse(raw));
  } catch (err) {
    if (err.code === "ENOENT") {
      return undefined;
    }
    throw err;
  }
}

function normalizeRetailerSessionStatus(status) {
  if (!status || typeof status !== "object" || Array.isArray(status)) {
    throw new TypeError("Retailer session status must be an object.");
  }

  const retailerIdentifier = normalizeString(status.retailerIdentifier, "retailerIdentifier");
  const normalizedStatus = normalizeString(status.status, "status");
  if (normalizedStatus !== RETAILER_SESSION_CONNECTED_STATUS) {
    throw new TypeError(`status must be ${RETAILER_SESSION_CONNECTED_STATUS}.`);
  }

  return {
    schemaVersion: RETAILER_SESSION_SCHEMA_VERSION,
    retailerIdentifier,
    status: normalizedStatus,
    connectedAt: normalizeTimestamp(status.connectedAt),
  };
}

async function openLoginPage(session, loginUrl) {
  if (session && typeof session.goto === "function") {
    await session.goto(loginUrl);
    return;
  }
  if (session && typeof session.navigate === "function") {
    await session.navigate(loginUrl);
    return;
  }
  if (session && typeof session.open === "function") {
    await session.open(loginUrl);
  }
}

async function waitForAsketAuthentication(session, waitForAuthenticated, loginUrl) {
  if (typeof waitForAuthenticated === "function") {
    return Boolean(
      await waitForAuthenticated({
        loginUrl,
        retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
        session,
      }),
    );
  }
  if (session && typeof session.waitForAuthenticated === "function") {
    return Boolean(
      await session.waitForAuthenticated({
        loginUrl,
        retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
      }),
    );
  }
  throw new TypeError("waitForAuthenticated must be a function.");
}

function normalizeString(value, field) {
  if (typeof value !== "string" || !value.trim()) {
    throw new TypeError(`${field} must be a non-empty string.`);
  }
  return value.trim();
}

function normalizeTimestamp(value) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) {
    throw new TypeError("connectedAt must be a valid date or ISO timestamp.");
  }
  return date.toISOString();
}

import { mkdtemp, readFile, rm, stat } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import test from "node:test";
import assert from "node:assert/strict";

import {
  ASKET_LOGIN_URL,
  ASKET_RETAILER_IDENTIFIER,
  RETAILER_SESSION_CONNECTED_STATUS,
  RETAILER_SESSION_STATUS_FILE,
  readAsketConnectedRetailers,
  readAsketConnectionStatus,
  startAsketLoginFlow,
} from "../src/asket-login-flow.mjs";

test("opens Asket login in a visible persistent profile and records connected status", async () => {
  const profilesRoot = await mkProfileRoot();
  const events = [];
  const session = {
    async setWindowTitle(title) {
      events.push(["title", title]);
    },
    async foreground() {
      events.push(["foreground"]);
    },
    async goto(url) {
      events.push(["goto", url]);
    },
    async background() {
      events.push(["background"]);
    },
  };
  const launcher = {
    async launch(options) {
      events.push(["launch", options]);
      await stat(options.userDataDir);
      return session;
    },
  };

  try {
    const result = await startAsketLoginFlow({
      launcher,
      profilesRoot,
      now: new Date("2026-05-09T12:00:00.000Z"),
      waitForAuthenticated: async ({ loginUrl, retailerIdentifier, session: callbackSession }) => {
        assert.equal(loginUrl, ASKET_LOGIN_URL);
        assert.equal(retailerIdentifier, ASKET_RETAILER_IDENTIFIER);
        assert.equal(callbackSession, session);
        events.push(["authenticated"]);
        return true;
      },
    });

    assert.equal(result.retailerIdentifier, ASKET_RETAILER_IDENTIFIER);
    assert.equal(result.status, RETAILER_SESSION_CONNECTED_STATUS);
    assert.equal(result.sessionStatus.connectedAt, "2026-05-09T12:00:00.000Z");
    assert.equal(result.profile.userDataDir, result.profile.profileDirectory);

    assert.deepEqual(
      events.map((event) => event[0]),
      ["launch", "title", "foreground", "goto", "authenticated", "background"],
    );
    assert.equal(events[0][1].retailer, ASKET_RETAILER_IDENTIFIER);
    assert.equal(events[0][1].headless, false);
    assert.equal(events[0][1].loginUrl, ASKET_LOGIN_URL);
    assert.equal(events[0][1].startUrl, ASKET_LOGIN_URL);
    assert.equal(events[0][1].userDataDir, result.profile.profileDirectory);

    const stored = JSON.parse(
      await readFile(join(result.profile.profileDirectory, RETAILER_SESSION_STATUS_FILE), "utf8"),
    );
    assert.deepEqual(stored, {
      schemaVersion: 1,
      retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
      status: RETAILER_SESSION_CONNECTED_STATUS,
      connectedAt: "2026-05-09T12:00:00.000Z",
    });
  } finally {
    await rm(profilesRoot, { recursive: true, force: true });
  }
});

test("connection status survives a later read from the same browser profile root", async () => {
  const profilesRoot = await mkProfileRoot();
  const launcher = {
    async launch() {
      return {
        async navigate() {},
      };
    },
  };

  try {
    await startAsketLoginFlow({
      launcher,
      profilesRoot,
      now: new Date("2026-05-09T13:00:00.000Z"),
      waitForAuthenticated: async () => true,
    });

    const reloaded = await readAsketConnectionStatus(profilesRoot);
    const connectedRetailers = await readAsketConnectedRetailers(profilesRoot);

    assert.deepEqual(reloaded, {
      schemaVersion: 1,
      retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
      status: RETAILER_SESSION_CONNECTED_STATUS,
      connectedAt: "2026-05-09T13:00:00.000Z",
    });
    assert.deepEqual(connectedRetailers, [
      {
        retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
        status: "Connected",
      },
    ]);
  } finally {
    await rm(profilesRoot, { recursive: true, force: true });
  }
});

test("does not mark Asket connected when authentication does not complete", async () => {
  const profilesRoot = await mkProfileRoot();
  const launcher = {
    async launch() {
      return {
        async open() {},
      };
    },
  };

  try {
    await assert.rejects(
      () =>
        startAsketLoginFlow({
          launcher,
          profilesRoot,
          waitForAuthenticated: async () => false,
        }),
      /Asket authentication did not complete/,
    );

    assert.equal(await readAsketConnectionStatus(profilesRoot), undefined);
    assert.deepEqual(await readAsketConnectedRetailers(profilesRoot), []);
  } finally {
    await rm(profilesRoot, { recursive: true, force: true });
  }
});

async function mkProfileRoot() {
  return mkdtemp(join(tmpdir(), "asket-login-flow-"));
}

export const AUTOMATION_BROWSER_WAITING_MESSAGE = "Waiting…";
export const AUTOMATION_BROWSER_TITLE_PREFIX = "Bestfriend";

export function createAutomationBrowserTitle(retailer) {
  return `${AUTOMATION_BROWSER_TITLE_PREFIX} · ${normalizeRetailer(retailer)}`;
}

export class VisibleAutomationBrowserRun {
  constructor({ launcher, windowManager = {}, chat = {} } = {}) {
    if (!launcher || typeof launcher.launch !== "function") {
      throw new TypeError("launcher.launch must be a function.");
    }

    this.launcher = launcher;
    this.windowManager = windowManager;
    this.chat = chat;
    this.current = undefined;
  }

  async startStagingRun({ retailer, headless = false, ...launchOptions } = {}) {
    if (this.current) {
      throw new Error("An automation browser run is already active.");
    }

    const normalizedRetailer = normalizeRetailer(retailer);
    const normalizedHeadless = normalizeBoolean(headless, "headless");
    const title = createAutomationBrowserTitle(normalizedRetailer);
    const session = await this.launcher.launch({
      ...launchOptions,
      retailer: normalizedRetailer,
      title,
      headless: normalizedHeadless,
    });

    this.current = {
      headless: normalizedHeadless,
      retailer: normalizedRetailer,
      session,
      title,
      userActionNeeded: false,
    };

    await setBrowserTitle({ session, windowManager: this.windowManager, title });

    if (!normalizedHeadless) {
      await foregroundBrowser({ session, windowManager: this.windowManager });
    }

    return {
      headless: normalizedHeadless,
      retailer: normalizedRetailer,
      title,
    };
  }

  async waitForUserAction({ reason = "challenge" } = {}) {
    const run = this.requireCurrentRun();
    run.userActionNeeded = true;

    await publishWaiting(this.chat, {
      message: AUTOMATION_BROWSER_WAITING_MESSAGE,
      reason,
      retailer: run.retailer,
      session: run.session,
    });

    return {
      message: AUTOMATION_BROWSER_WAITING_MESSAGE,
      reason,
      status: "waiting",
    };
  }

  async completeSuccessfully() {
    const run = this.requireCurrentRun();

    if (run.userActionNeeded) {
      return {
        message: AUTOMATION_BROWSER_WAITING_MESSAGE,
        status: "waiting",
      };
    }

    if (!run.headless) {
      await backgroundBrowser({ session: run.session, windowManager: this.windowManager });
    }

    this.current = undefined;

    return {
      status: "succeeded",
    };
  }

  get isActive() {
    return Boolean(this.current);
  }

  requireCurrentRun() {
    if (!this.current) {
      throw new Error("No automation browser run is active.");
    }
    return this.current;
  }
}

async function setBrowserTitle({ session, windowManager, title }) {
  if (session && typeof session.setWindowTitle === "function") {
    await session.setWindowTitle(title);
    return;
  }
  if (typeof windowManager.setTitle === "function") {
    await windowManager.setTitle(session, title);
  }
}

async function foregroundBrowser({ session, windowManager }) {
  if (session && typeof session.foreground === "function") {
    await session.foreground();
    return;
  }
  if (typeof windowManager.foreground === "function") {
    await windowManager.foreground(session);
  }
}

async function backgroundBrowser({ session, windowManager }) {
  if (session && typeof session.background === "function") {
    await session.background();
    return;
  }
  if (typeof windowManager.background === "function") {
    await windowManager.background(session);
  }
}

async function publishWaiting(chat, payload) {
  if (typeof chat.showWaiting === "function") {
    await chat.showWaiting(payload.message, payload);
    return;
  }
  if (typeof chat.setStatus === "function") {
    await chat.setStatus(payload.message, payload);
    return;
  }
  if (typeof chat === "function") {
    await chat(payload.message, payload);
  }
}

function normalizeRetailer(retailer) {
  if (typeof retailer !== "string" || !retailer.trim()) {
    throw new TypeError("retailer must be a non-empty string.");
  }
  return retailer.trim();
}

function normalizeBoolean(value, field) {
  if (typeof value !== "boolean") {
    throw new TypeError(`${field} must be a boolean.`);
  }
  return value;
}

import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";

export const SHOPPING_PROFILE_SCHEMA_VERSION = 1;
export const DEFAULT_SHOPPING_PROFILE_PATH = "data/shopping-profile.json";

export function createDefaultShoppingProfile(overrides = {}) {
  return normalizeShoppingProfile({
    country: "LV",
    currency: "EUR",
    sizes: {},
    budgetAnchors: {},
    hardExclusions: [],
    perItemPriceCeiling: { amount: 0, currency: "EUR" },
    enabledRetailers: [],
    ...overrides,
  });
}

export async function readShoppingProfile(filePath = DEFAULT_SHOPPING_PROFILE_PATH) {
  try {
    const raw = await readFile(resolve(filePath), "utf8");
    return normalizeShoppingProfile(JSON.parse(raw));
  } catch (err) {
    if (err.code === "ENOENT") {
      return createDefaultShoppingProfile();
    }
    throw err;
  }
}

export async function writeShoppingProfile(profile, filePath = DEFAULT_SHOPPING_PROFILE_PATH) {
  const normalized = normalizeShoppingProfile(profile);
  const target = resolve(filePath);
  await mkdir(dirname(target), { recursive: true });
  await writeFile(target, `${JSON.stringify(normalized, null, 2)}\n`, "utf8");
  return normalized;
}

export async function updateShoppingProfile(patch, filePath = DEFAULT_SHOPPING_PROFILE_PATH) {
  const current = await readShoppingProfile(filePath);
  const next = normalizeShoppingProfile({
    ...current,
    ...patch,
    sizes: patch.sizes ? { ...current.sizes, ...patch.sizes } : current.sizes,
    budgetAnchors: patch.budgetAnchors
      ? { ...current.budgetAnchors, ...patch.budgetAnchors }
      : current.budgetAnchors,
  });
  return writeShoppingProfile(next, filePath);
}

export function normalizeShoppingProfile(profile) {
  if (!profile || typeof profile !== "object" || Array.isArray(profile)) {
    throw new TypeError("Shopping profile must be an object.");
  }

  const country = normalizeCode(profile.country, "country", 2);
  const currency = normalizeCode(profile.currency, "currency", 3);
  const perItemPriceCeiling = normalizeMoney(
    profile.perItemPriceCeiling,
    "perItemPriceCeiling",
    currency,
  );

  return {
    schemaVersion: SHOPPING_PROFILE_SCHEMA_VERSION,
    country,
    currency,
    sizes: normalizeRecord(profile.sizes, "sizes", normalizeSize),
    budgetAnchors: normalizeRecord(profile.budgetAnchors, "budgetAnchors", (value, key) =>
      normalizeBudgetAnchor(value, key, currency),
    ),
    hardExclusions: normalizeUniqueStringArray(profile.hardExclusions, "hardExclusions"),
    perItemPriceCeiling,
    enabledRetailers: normalizeUniqueStringArray(profile.enabledRetailers, "enabledRetailers"),
  };
}

function normalizeCode(value, field, length) {
  if (typeof value !== "string") {
    throw new TypeError(`${field} must be a string.`);
  }
  const normalized = value.trim().toUpperCase();
  if (!new RegExp(`^[A-Z]{${length}}$`).test(normalized)) {
    throw new TypeError(`${field} must be a ${length}-letter uppercase code.`);
  }
  return normalized;
}

function normalizeRecord(value, field, normalizeValue) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new TypeError(`${field} must be an object.`);
  }

  return Object.fromEntries(
    Object.entries(value).map(([key, item]) => {
      const normalizedKey = String(key).trim();
      if (!normalizedKey) {
        throw new TypeError(`${field} keys must be non-empty strings.`);
      }
      return [normalizedKey, normalizeValue(item, normalizedKey)];
    }),
  );
}

function normalizeSize(value, key) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new TypeError(`sizes.${key} must be an object.`);
  }
  if (typeof value.value !== "string" || !value.value.trim()) {
    throw new TypeError(`sizes.${key}.value must be a non-empty string.`);
  }

  const normalized = { value: value.value.trim() };
  if (value.system !== undefined) {
    if (typeof value.system !== "string" || !value.system.trim()) {
      throw new TypeError(`sizes.${key}.system must be a non-empty string.`);
    }
    normalized.system = value.system.trim();
  }
  if (value.notes !== undefined) {
    if (typeof value.notes !== "string") {
      throw new TypeError(`sizes.${key}.notes must be a string.`);
    }
    normalized.notes = value.notes.trim();
  }
  return normalized;
}

function normalizeMoney(value, field, defaultCurrency) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new TypeError(`${field} must be an object.`);
  }
  if (typeof value.amount !== "number" || !Number.isFinite(value.amount) || value.amount < 0) {
    throw new TypeError(`${field}.amount must be a non-negative finite number.`);
  }

  return {
    amount: value.amount,
    currency:
      value.currency === undefined
        ? defaultCurrency
        : normalizeCode(value.currency, `${field}.currency`, 3),
  };
}

function normalizeBudgetAnchor(value, key, defaultCurrency) {
  const field = `budgetAnchors.${key}`;
  const normalized = normalizeMoney(value, field, defaultCurrency);

  if (value.cadence !== undefined) {
    if (!["per_item", "monthly", "seasonal", "annual"].includes(value.cadence)) {
      throw new TypeError(`${field}.cadence must be per_item, monthly, seasonal, or annual.`);
    }
    normalized.cadence = value.cadence;
  }
  if (value.notes !== undefined) {
    if (typeof value.notes !== "string") {
      throw new TypeError(`${field}.notes must be a string.`);
    }
    normalized.notes = value.notes.trim();
  }

  return normalized;
}

function normalizeUniqueStringArray(value, field) {
  if (!Array.isArray(value)) {
    throw new TypeError(`${field} must be an array.`);
  }

  return [...new Set(value.map((item) => {
    if (typeof item !== "string" || !item.trim()) {
      throw new TypeError(`${field} entries must be non-empty strings.`);
    }
    return item.trim();
  }))];
}

